VALUES
  ('social-worker-moex-02881', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '早期英國的慈善組織會社（Charity Organization Society, COS）所採取的是以下何種早期社會工作原則？', '["高蘭（Galan）的危機介入原則", "查墨斯（Thomas Chalmers）的睦鄰原則", "佛洛依德（Freud）的心理分析原則", "巴克雷（Barclay）的社會照顧計畫原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02882', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作倫理相關理論中，有一個理論持有以下的假設：「社會之善乃個人之善的總合」，請問是下列 那一種理論觀點？', '["德行論", "效用主義", "馬克思主義", "康德主義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02883', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於「依附理論」（attachment theory），下列那一個敘述是錯誤的？', '["照顧者的心智會與嬰兒的心智相通，稱為「心心相遇的交互主觀」（mind-to-mind encounter intersubjectivity）", "兒童要發展出安全的依附關係，需要有敏感而情緒調和的照顧者", "照顧者冷漠、嚴苛，或是拒絕孩子的需求，小孩有可能發展出「逃避依附」（avoidant attachment）", "「依附理論」（attachment theory）認為依附妨礙獨立，所以主張最好不要依附"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02884', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社會工作理論中的「問題解決模型」，下列描述何者是錯誤的？', '["強調一起工作的人（person）、待處理的問題（problem），工作地點（place）以及工作過程（process）", "認為解決問題的關鍵，主要是在問題解決的機率（probability）", "代表人物是波爾曼（Helen Perlman）", "受到自我心理學（ego psychology）的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02885', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下有關精神分析理論（Psychoanalysis）內容的描述，何者錯誤？', '["強調性心理發展階段（stage of psychosexual development）", "提出人格的組成包含本我、自我及超我三大部分", "主張人的心靈應包含意識、前意識與潛意識等三部分", "重視人與人的互動經驗，透過互動方能進入他人意識的世界"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02886', 'social-worker', 'social-worker-moex-102-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關社會工作常見理論的描述，何者錯誤？', '["精神分析觀點，強調個人的潛意識決定行為", "危機介入模型，認為個人在壓力情境時，會出現不同以往慣用的問題解決方法，進而導致個人遭遇危機", "社會網絡干預模型，認為當個人社會網絡欠缺與社會支持不足時，個人會產生社會疏離行為", "基變社會工作，強調資本主義下的政治與經濟結構對於弱勢族群造成不公平、壓迫和疏離，是造成案 主問題的根源"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "1ff41e73369f", "answer_pdf_sha1": "2545f2c9ffe8", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02887', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '特別重視員工必須從組織中的管理者或其他人身上獲得積極的關注與回應，也就是重視組織中的非正式 關係。此一管理觀點屬於：', '["科學管理", "人際關係學派", "系統理論", "新管理主義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02888', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列何者是新管理主義對社會工作管理所產生的影響？', '["重視職場靈性", "強調人性化管理", "重視績效管理", "強調科層組織分工"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02889', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當前政府的許多社會福利服務輸送是透過購買式服務契約的方式。影響購買式服務契約的管理觀點為何？', '["新管理主義", "新公共服務", "批判管理研究", "新韋伯國家（New Weberian State）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02890', 'social-worker', 'social-worker-moex-102-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '如何形塑組織使其更具效率是管理學重要的研究課題，在管理思潮的發展過程中，兼顧「組織」與「員 工」的技術與心理需求，並重視內外環境的理論觀點，下列何者正確？', '["古典觀點", "人群關係觀點", "系統觀點", "權變觀點"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:14+00:00", "source_pdf_sha1": "f9469744500c", "answer_pdf_sha1": "07df2aebbe74", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0703", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
